/**
 * Markdown documentation example.
 * 
 * # Heading 1
 * ## Heading 2
 * 
 * This function supports:
 * - **Bold text**
 * - *Italic text*
 * - `code snippets`
 * - [Links](https://example.com)
 * 
 * ```javascript
 * // Code block example
 * const result = markdownExample(42);
 * console.log(result);
 * ```
 * 
 * > This is a blockquote
 * 
 * @param {number} value - Input value
 * @returns {number} Doubled value
 */
function markdownExample(value) {
    return value * 2;
}
